                                    <span>Aceleração do Mouse ativada</span>
                                </label>
                            </div>
                        </div>
                    </div>
                )}

                {step === 5 && (
                    <div className={styles.fadeIn}>
                        <h3 className={styles.stepTitle}>📐 Espaço Físico</h3>
                        <p className={styles.stepDesc}>Espaço disponível para movimentar o mouse e comprimento do braço.</p>
                        <div className={styles.formGrid}>
                            <div className={styles.field}>
                                <label className="input-label">Comprimento do Braço *</label>
                                <div className={styles.optionGrid}>
                                    {(['short', 'medium', 'long'] as const).map(a => (
                                        <button key={a} type="button"
                                            className={`${styles.optionCard} ${form.physical.armLength === a ? styles.optionActive : ''}`}
                                            onClick={() => updateField('physical', 'armLength', a)}
                                            aria-pressed={form.physical.armLength === a}
                                        >
                                            <span className={styles.optionName}>{a === 'short' ? 'Curto' : a === 'medium' ? 'Médio' : 'Longo'}</span>
                                        </button>
                                    ))}
                                </div>
                            </div>
                            <div className={styles.field}>
                                <label className="input-label" htmlFor="desk-space">Espaço na Mesa (cm) *</label>
                                <div className={styles.sliderRow}>
                                    <input id="desk-space" type="range" className="slider" min={20} max={200} value={form.physical.deskSpaceCm} onChange={e => updateField('physical', 'deskSpaceCm', Number(e.target.value))} />
                                    <span className={styles.sliderValue}>{form.physical.deskSpaceCm} cm</span>
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* Result message */}
            {result && (
                <div className={`${styles.result} ${result.success ? styles.resultSuccess : styles.resultError}`}>
                    {result.success ? '✅ Perfil salvo com sucesso!' : `❌ ${result.error}`}
                </div>
            )}

            {/* Navigation buttons */}
            <div className={styles.navButtons}>
                <button className="btn btn-ghost" onClick={() => setStep(s => s - 1)} disabled={!canGoBack}>
                    ← Voltar
                </button>

                {isLastStep ? (
                    <button className="btn btn-primary btn-lg" onClick={handleSubmit} disabled={saving}>
                        {saving ? '⏳ Salvando...' : '💾 Salvar Perfil'}
                    </button>
                ) : (
                    <button className="btn btn-primary" onClick={() => setStep(s => s + 1)} disabled={!canGoNext}>
                        Próximo →
                    </button>
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useTransition, useEffect } from 'react';
import { Control, useForm, useWatch } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { playerProfileSchema } from '@/types/schemas';
import type { z } from 'zod';
import type { playerProfiles } from '@/db/schema';
import { saveProfile, deleteUserAccount } from '@/actions/profile';
import styles from './settings-form.module.css';

const MOUSE_SENSORS = ['Logitech HERO', 'PixArt PAW3395', 'PixArt PAW3370', 'Focus Pro 30K', 'TrueMove', 'Outro Sensor'];
const GRIP_STYLES = ['palm', 'claw', 'fingertip', 'hybrid'];
const PLAY_STYLES = ['arm', 'wrist', 'hybrid'];
const MOUSEPAD_TYPES = ['speed', 'control', 'hybrid'];
const MOUSEPAD_MATERIALS = ['cloth', 'hard', 'glass'];
const MONITOR_PANELS = ['ips', 'tn', 'va'];

type ProfileFormValues = z.infer<typeof playerProfileSchema>;

// Sub-component for performance optimization: Only re-renders when DPI or Sensitivity changes
// eslint-disable-next-line @typescript-eslint/no-explicit-any
function Cm360Badge({ control }: { control: any }) {
    const currentDpi = useWatch({ control, name: 'mouse.dpi' }) || 800;
    const currentSens = useWatch({ control, name: 'pubgSettings.generalSens' }) || 35;
    const calculatedCm360 = Math.round(((800 / currentDpi) * (35 / currentSens) * 43.2) * 10) / 10;

    return (
        <div className={styles.cmBadge}>
            {calculatedCm360} cm/360°
        </div>
    );
}

export function SettingsForm({ initialData }: { initialData: typeof playerProfiles.$inferSelect | null }) {
    const [isPending, startTransition] = useTransition();
    const [isDeleting, setIsDeleting] = useState(false);
    const [notification, setNotification] = useState<{ type: 'success' | 'error', message: string } | null>(null);
    const [activeTab, setActiveTab] = useState<'identity' | 'mouse' | 'mousepad' | 'ingame' | 'danger'>('identity');

    const defaultValues: Partial<ProfileFormValues> = initialData ? {
        identity: {
            bio: initialData.bio || '',
            twitter: initialData.twitter || '',
            twitch: initialData.twitch || '',
        },
        mouse: {
            model: initialData.mouseModel || '',
            sensor: initialData.mouseSensor || '',
            dpi: initialData.mouseDpi || 800,
            pollingRate: initialData.mousePollingRate || 1000,
            weightGrams: initialData.mouseWeight || 60,
            liftOffDistance: initialData.mouseLod || 1.0,
        },
        mousepad: {
            model: initialData.mousepadModel || '',
            widthCm: initialData.mousepadWidth || 45,
            heightCm: initialData.mousepadHeight || 40,
            type: (initialData.mousepadType as 'hybrid' | 'speed' | 'control') || 'control',
            material: (initialData.mousepadMaterial as 'cloth' | 'hard' | 'glass') || 'cloth',
        },
        gripStyle: (initialData.gripStyle as 'palm' | 'claw' | 'fingertip' | 'hybrid') || 'palm',
        playStyle: (initialData.playStyle as 'arm' | 'wrist' | 'hybrid') || 'arm',
        monitor: {
            resolution: initialData.monitorResolution || '1920x1080',
            refreshRate: initialData.monitorRefreshRate || 144,
            panelType: (initialData.monitorPanel as 'ips' | 'tn' | 'va') || 'ips',
        },
        pubgSettings: {
            generalSens: initialData.generalSens || 35,
            adsSens: initialData.adsSens || 30,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            scopeSens: (initialData.scopeSens as any) || { '1x': 30, '2x': 30, '3x': 30, '4x': 30, '6x': 30, '8x': 30, '15x': 30 },
            fov: initialData.fov || 90,
            verticalMultiplier: initialData.verticalMultiplier || 1.0,
            mouseAcceleration: initialData.mouseAcceleration || false,
        },
        physical: {
            armLength: (initialData.armLength as 'short' | 'medium' | 'long') || 'medium',
            deskSpaceCm: initialData.deskSpace || 60,
        },
    } : {
        identity: { bio: '', twitter: '', twitch: '' },
        mouse: { model: '', sensor: '', dpi: 800, pollingRate: 1000, weightGrams: 60, liftOffDistance: 1.0 },
        mousepad: { model: '', widthCm: 45, heightCm: 40, type: 'control', material: 'cloth' },
        monitor: { resolution: '1920x1080', refreshRate: 144, panelType: 'ips' },
        pubgSettings: {
            generalSens: 35,
            adsSens: 30,
            scopeSens: { '1x': 30, '2x': 30, '3x': 30, '4x': 30, '6x': 30, '8x': 30, '15x': 30 },
            fov: 90,
            verticalMultiplier: 1.0,
            mouseAcceleration: false,
        },
        physical: { armLength: 'medium', deskSpaceCm: 60 }
    };


     
    const { register, handleSubmit, formState: { errors, isDirty }, control, reset, setValue, getValues } = useForm<ProfileFormValues>({
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        resolver: zodResolver(playerProfileSchema) as any,
        defaultValues,
        mode: 'onChange'
    });

    // Sync form with initialData if it changes without full unmount
    useEffect(() => {
        if (initialData) {
            reset(defaultValues);
        }
    }, [initialData]);


    const syncAllScopes = () => {
        const currentAds = getValues('pubgSettings.adsSens') || 30;

        const newScopes = {
            '1x': currentAds,
            '2x': currentAds,
            '3x': currentAds,
            '4x': currentAds,
            '6x': currentAds,
            '8x': currentAds,
            '15x': currentAds,
        };

        setValue('pubgSettings.scopeSens', newScopes, {
            shouldDirty: true,
            shouldValidate: true,
            shouldTouch: true
        });
    };

    const onSubmit = (data: ProfileFormValues) => {
        setNotification(null);
        startTransition(async () => {
            const result = await saveProfile(data);

            if (result?.data?.success) {
                setNotification({ type: 'success', message: 'Configurações salvas com sucesso!' });
                reset(data); // Resets isDirty
                setTimeout(() => setNotification(null), 3000);
            } else if (result?.serverError) {
                setNotification({ type: 'error', message: result.serverError });
            } else if (result?.validationErrors) {
                setNotification({ type: 'error', message: 'Erro de validação, verifique os campos.' });
            } else {
                setNotification({ type: 'error', message: 'Erro desconhecido ao salvar o perfil.' });
            }
        });
    };

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const onError = (errors: any) => {
        setNotification({ type: 'error', message: 'Por favor, revise os campos marcados em vermelho nas abas de configuração.' });

        // Find the first tab that has an error and switch to it
        if (errors.identity) {
            setActiveTab('identity');
        } else if (errors.mouse || errors.monitor || errors.gripStyle || errors.playStyle) {
            setActiveTab('mouse');
        } else if (errors.mousepad || errors.physical) {
            setActiveTab('mousepad');
        } else if (errors.pubgSettings) {
            setActiveTab('ingame');
        }

        // Scroll to top of form area for visibility on mobile
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const handleDeleteAccount = async () => {
        if (!confirm('🚨 Atenção! Esta ação apagará SUA CONTA, TODOS os seus relatórios e vídeos e NÃO TEM VOLTA. Confirmar?')) return;

        setIsDeleting(true);
        const result = await deleteUserAccount();
        if (!result.success) {
            setNotification({ type: 'error', message: result.error || 'Erro ao deletar conta' });
            setIsDeleting(false);
        }
    };

    return (
        <div className={styles.layout}>
            {notification && (
                <div className={`${styles.toast} ${notification.type === 'success' ? styles.toastSuccess : styles.toastError}`}>
                    {notification.message}
                </div>
            )}

            {/* TABBED SIDEBAR */}
            <aside className={styles.sidebar}>
                <button
                    type="button"
                    className={`${styles.tabBtn} ${activeTab === 'identity' ? styles.tabActive : ''}`}
                    onClick={() => setActiveTab('identity')}
                >
                    👤 Identidade
                </button>
                <button
                    type="button"
                    className={`${styles.tabBtn} ${activeTab === 'mouse' ? styles.tabActive : ''}`}
                    onClick={() => setActiveTab('mouse')}
                >
                    🖱️ Mouse e Monitor
                </button>
                <button
                    type="button"
                    className={`${styles.tabBtn} ${activeTab === 'mousepad' ? styles.tabActive : ''}`}
                    onClick={() => setActiveTab('mousepad')}
                >
                    🟫 Mousepad
                </button>
                <button
                    type="button"
                    className={`${styles.tabBtn} ${activeTab === 'ingame' ? styles.tabActive : ''}`}
                    onClick={() => setActiveTab('ingame')}
                >
                    🎯 In-Game PUBG
                </button>
                <button
                    type="button"
                    className={`${styles.tabBtn} ${styles.dangerTabBtn} ${activeTab === 'danger' ? styles.dangerTabActive : ''}`}
                    onClick={() => setActiveTab('danger')}
                >
                    ⚠️ Danger Zone
                </button>
            </aside>

            {/* CONTENT AREA */}
            <form id="settings-form" onSubmit={handleSubmit(onSubmit, onError)} className={styles.contentArea}>

                {/* TAB: IDENTITY */}
                <div className={`${styles.tabPane} ${activeTab === 'identity' ? styles.tabPaneActive : ''}`}>
                    <div>
                        <h2 className={styles.sectionTitle}>Identidade e Sociais</h2>
                        <p className={styles.sectionDesc}>Esta informação aparecerá no seu perfil público e relatórios.</p>
                    </div>

                    <div className="glass-card">
                        <div className={styles.grid1}>
                            <div className="field">
                                <label className="input-label" htmlFor="bio">Sobre Mim (Bio)</label>
                                <textarea id="bio" rows={4} className={`input ${errors.identity?.bio ? styles.inputError : ''}`} placeholder="Me chamo X e jogo competitivamente..." {...register('identity.bio')} />
                                {errors.identity?.bio && <span className={styles.errorText}>{errors.identity.bio.message}</span>}
                            </div>
                        </div>
                        <div className={styles.grid2} style={{ marginTop: 'var(--space-lg)' }}>
                            <div className="field">
                                <label className="input-label" htmlFor="twitter">X (Twitter)</label>
                                <input id="twitter" className={`input ${errors.identity?.twitter ? styles.inputError : ''}`} placeholder="https://x.com/seuuser" {...register('identity.twitter')} />
                                {errors.identity?.twitter && <span className={styles.errorText}>{errors.identity.twitter.message}</span>}
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="twitch">Twitch</label>
                                <input id="twitch" className={`input ${errors.identity?.twitch ? styles.inputError : ''}`} placeholder="https://twitch.tv/seuuser" {...register('identity.twitch')} />
                                {errors.identity?.twitch && <span className={styles.errorText}>{errors.identity.twitch.message}</span>}
                            </div>
                        </div>
                    </div>
                </div>

                {/* TAB: MOUSE */}
                <div className={`${styles.tabPane} ${activeTab === 'mouse' ? styles.tabPaneActive : ''}`}>
                    <div>
                        <h2 className={styles.sectionTitle}>Mouse & Monitor</h2>
                        <p className={styles.sectionDesc}>Hardware base usado pela IA para extrapolar pixel skipping e input lag.</p>
                    </div>

                    <div className="glass-card">
                        <div className={styles.grid2}>
                            <div className="field">
                                <label className="input-label" htmlFor="mouse-model">Modelo do Mouse *</label>
                                <input id="mouse-model" className={`input ${errors.mouse?.model ? styles.inputError : ''}`} placeholder="G Pro X Superlight" {...register('mouse.model')} />
                                {errors.mouse?.model && <span className={styles.errorText}>{errors.mouse.model.message}</span>}
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="mouse-sensor">Sensor *</label>
                                <input id="mouse-sensor" list="sensors" className={`input ${errors.mouse?.sensor ? styles.inputError : ''}`} placeholder="HERO 25K" {...register('mouse.sensor')} />
                                <datalist id="sensors">{MOUSE_SENSORS.map(s => <option key={s} value={s} />)}</datalist>
                                {errors.mouse?.sensor && <span className={styles.errorText}>{errors.mouse.sensor.message}</span>}
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="mouse-dpi">DPI *</label>
                                <input id="mouse-dpi" type="number" className={`input ${errors.mouse?.dpi ? styles.inputError : ''}`} {...register('mouse.dpi')} />
                                {errors.mouse?.dpi && <span className={styles.errorText}>{errors.mouse.dpi.message}</span>}
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="mouse-polling">Polling Rate (Hz) *</label>
                                <select id="mouse-polling" className="input select" {...register('mouse.pollingRate')}>
                                    <option value="125">125 Hz</option>
                                    <option value="500">500 Hz</option>
                                    <option value="1000">1000 Hz</option>
                                    <option value="2000">2000 Hz</option>
                                    <option value="4000">4000 Hz</option>
                                    <option value="8000">8000 Hz</option>
                                </select>
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="mouse-weight">Peso (gramas) *</label>
                                <input id="mouse-weight" type="number" className={`input ${errors.mouse?.weightGrams ? styles.inputError : ''}`} {...register('mouse.weightGrams')} />
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="mouse-lod">Lift-Off Distance (mm) *</label>
                                <input id="mouse-lod" type="number" step="0.1" className={`input ${errors.mouse?.liftOffDistance ? styles.inputError : ''}`} {...register('mouse.liftOffDistance')} />
                            </div>
                        </div>

                        <hr style={{ margin: 'var(--space-xl) 0', border: 'none', borderTop: '1px solid rgba(255,255,255,0.05)' }} />

                        <div className={styles.grid2}>
                            <div className="field">
                                <label className="input-label" htmlFor="monitor-res">Resolução *</label>
                                <input id="monitor-res" className={`input ${errors.monitor?.resolution ? styles.inputError : ''}`} placeholder="1920x1080" {...register('monitor.resolution')} />
                                {errors.monitor?.resolution && <span className={styles.errorText}>{errors.monitor.resolution.message}</span>}
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="monitor-refresh">Refresh Rate (Hz) *</label>
                                <input id="monitor-refresh" type="number" className={`input ${errors.monitor?.refreshRate ? styles.inputError : ''}`} {...register('monitor.refreshRate')} />
                            </div>
                        </div>
                    </div>
                </div>

                {/* TAB: MOUSEPAD */}
                <div className={`${styles.tabPane} ${activeTab === 'mousepad' ? styles.tabPaneActive : ''}`}>
                    <div>
                        <h2 className={styles.sectionTitle}>Mousepad & Estilo Motriz</h2>
                        <p className={styles.sectionDesc}>Define o atrito dinâmico (CoD) nas equações de arrasto da AI.</p>
                    </div>

                    <div className="glass-card">
                        <div className={styles.grid2}>
                            <div className="field">
                                <label className="input-label" htmlFor="pad-model">Modelo do Mousepad *</label>
                                <input id="pad-model" className={`input ${errors.mousepad?.model ? styles.inputError : ''}`} placeholder="Artisan Hien" {...register('mousepad.model')} />
                                {errors.mousepad?.model && <span className={styles.errorText}>{errors.mousepad.model.message}</span>}
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="pad-type">Tipo de Superfície *</label>
                                <select id="pad-type" className="input select" {...register('mousepad.type')}>
                                    <option value="speed">Speed</option>
                                    <option value="control">Control</option>
                                    <option value="hybrid">Híbrido</option>
                                </select>
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="pad-material">Material *</label>
                                <select id="pad-material" className="input select" {...register('mousepad.material')}>
                                    <option value="cloth">Tecido (Cloth)</option>
                                    <option value="hard">Rígido (Hard)</option>
                                    <option value="glass">Vidro (Glass)</option>
                                </select>
                            </div>
                        </div>

                        <hr style={{ margin: 'var(--space-xl) 0', border: 'none', borderTop: '1px solid rgba(255,255,255,0.05)' }} />

                        <div className={styles.grid2}>
                            <div className="field">
                                <label className="input-label" htmlFor="grip">Estilo de Pegada (Grip) *</label>
                                <select id="grip" className="input select" {...register('gripStyle')}>
                                    <option value="palm">Palm Grip</option>
                                    <option value="claw">Claw Grip</option>
                                    <option value="fingertip">Fingertip Grip</option>
                                    <option value="hybrid">Híbrido</option>
                                </select>
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="play-style">Estilo Motriz *</label>
                                <select id="play-style" className="input select" {...register('playStyle')}>
                                    <option value="arm">Braço (Arm Aimer)</option>
                                    <option value="wrist">Pulso (Wrist Aimer)</option>
                                    <option value="hybrid">Híbrido</option>
                                </select>
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="deskspace">Espaço Livre no Setup (cm) *</label>
                                <input id="deskspace" type="number" className="input" {...register('physical.deskSpaceCm')} />
                            </div>
                        </div>
                    </div>
                </div>

                {/* TAB: INGAME */}
                <div className={`${styles.tabPane} ${activeTab === 'ingame' ? styles.tabPaneActive : ''}`}>
                    <div className={styles.badgeBadgeWrapper}>
                        <div>
                            <h2 className={styles.sectionTitle}>In-Game (PUBG)</h2>
                            <p className={styles.sectionDesc}>Configurações brutas do jogo.</p>
                        </div>
                        <Cm360Badge control={control} />
                    </div>

                    <div className="glass-card">
                        <div className={styles.grid2}>
                            <div className="field">
                                <label className="input-label" htmlFor="gen-sens">Sensibilidade Geral *</label>
                                <input id="gen-sens" type="number" step="0.1" className={`input ${errors.pubgSettings?.generalSens ? styles.inputError : ''}`} {...register('pubgSettings.generalSens')} />
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="ads-sens">Sensibilidade ADS (Mira) *</label>
                                <input id="ads-sens" type="number" step="0.1" className="input" {...register('pubgSettings.adsSens')} />
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="vert-mult">Multiplicador Vertical *</label>
                                <input id="vert-mult" type="number" step="0.01" className="input" {...register('pubgSettings.verticalMultiplier')} />
                            </div>
                            <div className="field">
                                <label className="input-label" htmlFor="fov">FOV (Campo de Visão) *</label>
                                <input id="fov" type="number" className="input" {...register('pubgSettings.fov')} />
                            </div>
                        </div>

                        <hr style={{ margin: 'var(--space-xl) 0', border: 'none', borderTop: '1px solid rgba(255,255,255,0.05)' }} />

                        <div>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 'var(--space-md)' }}>
                                <h3 style={{ fontSize: '1.1rem', margin: 0, color: 'var(--color-text)' }}>Sensibilidade por Mira (Scopes)</h3>
                                <button
                                    type="button"
                                    className="btn btn-secondary btn-sm"
                                    onClick={syncAllScopes}
                                    style={{ fontSize: '0.75rem', padding: '4px 12px' }}
                                >
                                    🔄 Sincronizar todas com ADS
                                </button>
                            </div>
                            <div className={styles.grid4}>
                                {(['1x', '2x', '3x', '4x', '6x', '8x', '15x'] as const).map((scope) => (
                                    <div className="field" key={scope}>
                                        <label className="input-label" htmlFor={`sens-${scope}`}>Mira {scope}</label>
                                        <input
                                            id={`sens-${scope}`}
                                            type="number"
                                            step="0.1"
                                            className="input"
                                            {...register(`pubgSettings.scopeSens.${scope}` as const)}
                                        />
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>

                {/* TAB: DANGER ZONE */}
                <div className={`${styles.tabPane} ${activeTab === 'danger' ? styles.tabPaneActive : ''}`}>
                    <div className={styles.dangerZone}>
                        <h2 className={`${styles.sectionTitle} ${styles.dangerTitle}`}>Apagar Conta</h2>
                        <p className={styles.sectionDesc} style={{ color: 'rgba(255, 74, 74, 0.8)' }}>
                            Isso apagará permanentemente seu perfil de hardware, todo o histórico de análises de spray e desfará o vínculo com os provedores de login (Google/Discord). Isso não pode ser desfeito.
                        </p>
                        <button
                            type="button"
                            className={styles.btnDanger}
                            onClick={handleDeleteAccount}
                            disabled={isDeleting}
                        >
                            {isDeleting ? 'Apagando dados...' : 'Excluir Minha Conta Definitivamente'}
                        </button>
                    </div>
                </div>

            </form>

            {/* FLOATING SAVE BAR */}
            <div className={`${styles.floatingSaveBar} ${isDirty ? styles.floatingSaveBarVisible : ''}`}>
                <span className={styles.saveBarText}>Você possui alterações não salvas.</span>
                <div className={styles.saveActions}>
                    <button type="button" className="btn btn-secondary" onClick={() => reset()} disabled={isPending}>Descartar</button>
                    <button type="submit" form="settings-form" className={styles.btnSave} disabled={isPending}>
                        {isPending ? 'Salvando...' : 'Salvar Alterações'}
                    </button>
                </div>
            </div>

        </div>
    );
}

'use client';

import { useState, startTransition } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { setupWizardSchema, type SetupWizardInput } from '@/types/schemas';
import { updateUserSetup } from '@/actions/setup';
import { useRouter } from 'next/navigation';

export function SetupForm({ initialData }: { initialData?: Partial<SetupWizardInput> }) {
    const router = useRouter();
    const [isPending, setIsPending] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const {
        register,
        handleSubmit,
        formState: { errors },
    } = useForm({
        resolver: zodResolver(setupWizardSchema),
        defaultValues: {
            resolution: initialData?.resolution || '1920x1080',
            fov: initialData?.fov || 90,
            mouseDpi: initialData?.mouseDpi || 800,
            sensGeneral: initialData?.sensGeneral || 50,
            sens1x: initialData?.sens1x || 50,
            sens3x: initialData?.sens3x || 50,
            sens4x: initialData?.sens4x || 50,
        },
    });

    const onSubmit = (data: any) => {
        const validatedData = data as SetupWizardInput;
        setIsPending(true);
        setError(null);
        startTransition(async () => {
            try {
                const result = await updateUserSetup(validatedData);
                if (result?.data?.success) {
                    router.push('/analyze');
                } else {
                    setError('Erro ao salvar configurações.');
                }
            } catch (err) {
                setError('Falha na comunicação com o servidor.');
            } finally {
                setIsPending(false);
            }
        });
    };

    return (
        <form onSubmit={handleSubmit(onSubmit)} className="animate-fade-in-up">
            <div className="glass-card-gradient space-y-6">
                <div className="space-y-2">
                    <h2 className="text-accent">Setup do Jogador</h2>
                    <p className="text-sm opacity-70">Configure seu hardware para análises precisas.</p>
                </div>

                {error && (
                    <div className="badge badge-error w-full py-2 text-center">
                        {error}
                    </div>
                )}

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Hardware Column */}
                    <div className="space-y-4">
                        <h3 className="text-lg font-bold border-b border-white/10 pb-2">Hardware</h3>

                        <div>
                            <label className="input-label">Resolução do Monitor</label>
                            <select {...register('resolution')} className="input select">
                                <option value="1920x1080">1920 x 1080 (FHD)</option>
                                <option value="2560x1440">2560 x 1440 (QHD)</option>
                                <option value="3840x2160">3840 x 2160 (4K)</option>
                                <option value="1728x1080">1728 x 1080 (Stretched)</option>
                                <option value="1600x900">1600 x 900</option>
                            </select>
                            {errors.resolution && <p className="text-error text-xs mt-1">{errors.resolution.message}</p>}
                        </div>

                        <div>
                            <label className="input-label">Mouse DPI</label>
                            <input
                                type="number"
                                {...register('mouseDpi', { valueAsNumber: true })}
                                className="input"
                                placeholder="ex: 800"
                            />
                            {errors.mouseDpi && <p className="text-error text-xs mt-1">{errors.mouseDpi.message}</p>}
                        </div>

                        <div>
                            <label className="input-label">PUBG FOV (Field of View)</label>
                            <input
                                type="number"
                                {...register('fov', { valueAsNumber: true })}
                                className="input"
                                placeholder="80 - 103"
                            />
                            {errors.fov && <p className="text-error text-xs mt-1">{errors.fov.message}</p>}
                        </div>
                    </div>

                    {/* Sensitivity Column */}
                    <div className="space-y-4">
                        <h3 className="text-lg font-bold border-b border-white/10 pb-2">Sensibilidade In-game</h3>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="input-label">Geral</label>
                                <input type="number" step="0.01" {...register('sensGeneral', { valueAsNumber: true })} className="input" />
                                {errors.sensGeneral && <p className="text-error text-xs mt-1">{errors.sensGeneral.message}</p>}
                            </div>
                            <div>
                                <label className="input-label">1x (Red Dot)</label>
                                <input type="number" step="0.01" {...register('sens1x', { valueAsNumber: true })} className="input" />
                                {errors.sens1x && <p className="text-error text-xs mt-1">{errors.sens1x.message}</p>}
                            </div>
                            <div>
                                <label className="input-label">3x Scope</label>
                                <input type="number" step="0.01" {...register('sens3x', { valueAsNumber: true })} className="input" />
                                {errors.sens3x && <p className="text-error text-xs mt-1">{errors.sens3x.message}</p>}
                            </div>
                            <div>
                                <label className="input-label">4x Scope</label>
                                <input type="number" step="0.01" {...register('sens4x', { valueAsNumber: true })} className="input" />
                                {errors.sens4x && <p className="text-error text-xs mt-1">{errors.sens4x.message}</p>}
                            </div>
                        </div>

                        <div className="pt-4 bg-accent/5 p-4 rounded-md border border-accent/20">
                            <p className="text-xs text-secondary italic">
                                * Estes dados são fundamentais para que nossa IA calcule o ajuste exato do seu eDPI com base no seu hardware real.
                            </p>
                        </div>
                    </div>
                </div>

                <div className="pt-6 flex justify-end">
                    <button
                        type="submit"
                        disabled={isPending}
                        className="btn btn-primary btn-lg w-full md:w-auto"
                    >
                        {isPending ? 'Salvando...' : 'Finalizar Configuração'}
                    </button>
                </div>
            </div>
        </form>
    );
}

/**
 * Crosshair Tracking — Rastreamento de mira frame-a-frame.
 * Color filtering (HSV) + centroid detection.
 * GPU accelerated via processing multiple frames.
 */

import { asPixels, asMilliseconds } from '../types/branded';
import type { Pixels, Milliseconds } from '../types/branded';
import type { TrackingPoint } from '../types/engine';
import type { ExtractedFrame } from './frame-extraction';

// ═══════════════════════════════════════════
// Configuration
// ═══════════════════════════════════════════

export interface TemplateMatchingConfig {
    /** Tamanho do template central em Frame 0 (pixel width/height). Pre-defined to 64x64. */
    readonly templateSize: number;
    /** O quão longe do local anterior procuramos o novo match (px) */
    readonly searchRadius: number;
}

const DEFAULT_CONFIG: TemplateMatchingConfig = {
    templateSize: 64,   // 64x64 center extraction
    searchRadius: 100,  // Procura até 100px pra cima/baixo/lados do ponto antigo
} as const;

// ═══════════════════════════════════════════
// Template Matching (SAD)
// ═══════════════════════════════════════════

interface DetectionResult {
    readonly found: boolean;
    readonly x: number;
    readonly y: number;
    readonly confidence: number;
}

/**
 * Calcula a Soma das Diferenças Absolutas (SAD) entre duas regiões.
 * Quanto menor o score, mais perfeito é o match.
 */
function calculateSAD(
    template: Uint8ClampedArray,
    templateW: number,
    templateH: number,
    searchData: Uint8ClampedArray,
    searchW: number,
    startX: number,
    startY: number
): number {
    let sad = 0;
    // Iterating per pixel (4 channels: RGBA)
    for (let y = 0; y < templateH; y++) {
        for (let x = 0; x < templateW; x++) {
            const tIdx = (y * templateW + x) * 4;
            const sIdx = ((startY + y) * searchW + (startX + x)) * 4;

            // Only compare RGB (ignore A)
            sad += Math.abs((template[tIdx] ?? 0) - (searchData[sIdx] ?? 0));
            sad += Math.abs((template[tIdx + 1] ?? 0) - (searchData[sIdx + 1] ?? 0));
            sad += Math.abs((template[tIdx + 2] ?? 0) - (searchData[sIdx + 2] ?? 0));
        }
    }
    return sad;
}

/**
 * Encontra um Template 64x64 dentro de uma área de busca (frame atual).
 */
function matchTemplate(
    templateData: Uint8ClampedArray,
    templateSize: number,
    frameData: ImageData,
    lastX: number,
    lastY: number,
    searchRadius: number
): DetectionResult {
    const { width: fw, height: fh, data: fdata } = frameData;

    // Define ROI (Bounding Box of the search)
    // We search around the PREVIOUS known position 'lastX', 'lastY'
    const startSearchX = Math.max(0, Math.floor(lastX - searchRadius));
    const startSearchY = Math.max(0, Math.floor(lastY - searchRadius));
    const endSearchX = Math.min(fw - templateSize, Math.floor(lastX + searchRadius));
    const endSearchY = Math.min(fh - templateSize, Math.floor(lastY + searchRadius));

    let bestSad = Infinity;
    let bestX = lastX;
    let bestY = lastY;

    // Slide the template over the search area
    // Optimizer: Instead of checking every single pixel (slow), we can check every 2nd or 3rd pixel for speed,
    // but SAD is fairly fast for a ~200x200 area on modern engines. We'll do strict per-2-pixel sliding for web performance.
    for (let y = startSearchY; y <= endSearchY; y += 2) {
        for (let x = startSearchX; x <= endSearchX; x += 2) {
            const sad = calculateSAD(templateData, templateSize, templateSize, fdata, fw, x, y);

            if (sad < bestSad) {
                bestSad = sad;
                bestX = x + (templateSize / 2); // Center of the matched template
                bestY = y + (templateSize / 2);
            }
        }
    }

    // Determine confidence based on SAD score (Perfect match = 0).
    const maxPossibleSAD = templateSize * templateSize * 3 * 255;
    const confidence = 1 - (bestSad / maxPossibleSAD);

    return {
        found: true,
        x: bestX,
        y: bestY,
        confidence: confidence > 0.85 ? confidence : Math.max(0, (confidence - 0.5) * 2), // Boost the penalty on bad matches
    };
}

// ═══════════════════════════════════════════
// Track All Frames
// ═══════════════════════════════════════════

export interface TrackingResult {
    readonly points: readonly TrackingPoint[];
    readonly trackingQuality: number; // 0-1
    readonly framesTracked: number;
    readonly framesLost: number;
}

/**
 * Rastreia o crosshair em todos os frames extraídos.
 * Retorna TrackingPoints com posição, timestamp e confiança.
 */
export function trackCrosshair(
    frames: readonly ExtractedFrame[],
    config?: Partial<TemplateMatchingConfig>
): TrackingResult {
    const fullConfig = { ...DEFAULT_CONFIG, ...config };
    const points: TrackingPoint[] = [];
    let framesLost = 0;

    if (frames.length === 0) return { points: [], trackingQuality: 0, framesTracked: 0, framesLost: 0 };

    const firstFrame = frames[0]!;
    const fw = firstFrame.imageData.width;
    const fh = firstFrame.imageData.height;

    // Center starting point
    let lastX = fw / 2;
    let lastY = fh / 2;

    // Extract the Template from Frame 0
    // To do this natively without Canvas ctx, we manually copy the ArrayBuffer slice
    const tSize = fullConfig.templateSize;
    const tStartX = Math.floor(lastX - (tSize / 2));
    const tStartY = Math.floor(lastY - (tSize / 2));

    const templateData = new Uint8ClampedArray(tSize * tSize * 4);
    for (let ty = 0; ty < tSize; ty++) {
        for (let tx = 0; tx < tSize; tx++) {
            const frameIdx = ((tStartY + ty) * fw + (tStartX + tx)) * 4;
            const tplIdx = (ty * tSize + tx) * 4;
            templateData[tplIdx] = firstFrame.imageData.data[frameIdx] ?? 0;
            templateData[tplIdx + 1] = firstFrame.imageData.data[frameIdx + 1] ?? 0;
            templateData[tplIdx + 2] = firstFrame.imageData.data[frameIdx + 2] ?? 0;
            templateData[tplIdx + 3] = 255;
        }
    }

    // Force frame 0 point exactly at center
    points.push({
        frame: firstFrame.index,
        timestamp: asMilliseconds(firstFrame.timestamp),
        x: asPixels(lastX),
        y: asPixels(lastY),
        confidence: 1.0,
    });

    for (let i = 1; i < frames.length; i++) {
        const frame = frames[i]!;

        // Match the background pattern
        const result = matchTemplate(templateData, tSize, frame.imageData, lastX, lastY, fullConfig.searchRadius);

        if (result.confidence > 0.4) {
            points.push({
                frame: frame.index,
                timestamp: asMilliseconds(frame.timestamp),
                x: asPixels(result.x),
                y: asPixels(result.y),
                confidence: result.confidence,
            });
            lastX = result.x;
            lastY = result.y; // Clean tracking without artificial recoil bias
        } else {
            framesLost++;
            points.push({
                frame: frame.index,
                timestamp: asMilliseconds(frame.timestamp),
                x: asPixels(lastX),
                y: asPixels(lastY),
                confidence: result.confidence,
            });
        }
    }

    const tracked = frames.length - framesLost;
    const quality = frames.length > 0 ? tracked / frames.length : 0;

    return {
        points,
        trackingQuality: quality,
        framesTracked: tracked,
        framesLost,
    };
}

